(function(){
  const svg = $('#pt-svg'), out = $('#pt-out'), sel = $('#pt-ring');
  function compute(k){
    if(k==='R'){
      return {kind:'plot'};
    }
    if(k==='Q' || k==='Z'){
      const hits = [];
      for(let a=-6; a<=6; a++) for(let b=-6; b<=6; b++){
        if(b*b === a*a*a + 1) hits.push([a,b]);
      }
      return {kind:'list', field:k==='Q'?'\u211A':'\u2124', pts:hits, note:'(integer solutions with |a|,|b| \u2264 6)'};
    }
    const p = +k.slice(1);
    const pts = [];
    for(let a=0;a<p;a++) for(let b=0;b<p;b++){
      if(((b*b - a*a*a - 1) % p + p) % p === 0) pts.push([a,b]);
    }
    return {kind:'finite', p, pts};
  }
  function render(){
    while(svg.firstChild) svg.removeChild(svg.firstChild);
    const res = compute(sel.value);
    if(res.kind==='plot'){
      // draw y^2 = x^3 + 1 over R
      const cx=320, cy=130, sx=40, sy=40;
      // axes
      svg.appendChild(SVG('line',{x1:40,y1:cy,x2:600,y2:cy,stroke:'var(--line)'}));
      svg.appendChild(SVG('line',{x1:cx,y1:20,x2:cx,y2:240,stroke:'var(--line)'}));
      const pts = [];
      for(let t=-1; t<=4; t+=0.02){
        const xv = t;
        const rhs = xv*xv*xv + 1;
        if(rhs<0) continue;
        const yv = Math.sqrt(rhs);
        const px = cx + xv*sx, py = cy - yv*sy;
        pts.push([px,py]);
      }
      if(pts.length){
        const dUp = 'M '+pts.map(p=>p.join(' ')).join(' L ');
        svg.appendChild(SVG('path',{d:dUp,stroke:'var(--yellow)','stroke-width':2,fill:'none'}));
        const dDown = 'M '+pts.map(p=>[p[0], 2*cy-p[1]].join(' ')).join(' L ');
        svg.appendChild(SVG('path',{d:dDown,stroke:'var(--yellow)','stroke-width':2,fill:'none'}));
      }
      // axis ticks
      for(let i=-1;i<=5;i++){
        const tx = SVG('text',{x:cx+i*sx,y:cy+14,'text-anchor':'middle','font-size':10,fill:'var(--mute)'});
        tx.textContent = i; svg.appendChild(tx);
      }
      const label = SVG('text',{x:500,y:40,'text-anchor':'end','font-size':12,fill:'var(--mute)'});
      label.textContent = 'smooth real curve (no rational points on this branch matter here)';
      svg.appendChild(label);
      out.textContent = 'X(\u211D) is the solution locus of y^2 = x^3 + 1 in \u211D^2.  One connected component.  Uncountable.';
      return;
    }
    if(res.kind==='list'){
      out.textContent = `X(${res.field}) small search: ${res.pts.length} solutions\n  ` +
        res.pts.map(([a,b])=>`(${a},${b})`).join('  ') + `\n${res.note}`;
      // Plot the lattice
      const cx=320, cy=130, sx=30, sy=30;
      svg.appendChild(SVG('line',{x1:40,y1:cy,x2:600,y2:cy,stroke:'var(--line)'}));
      svg.appendChild(SVG('line',{x1:cx,y1:20,x2:cx,y2:240,stroke:'var(--line)'}));
      for(let i=-6;i<=6;i++){
        const tx = SVG('text',{x:cx+i*sx,y:cy+14,'text-anchor':'middle','font-size':10,fill:'var(--mute)'});
        tx.textContent = i; svg.appendChild(tx);
      }
      for(const [a,b] of res.pts){
        svg.appendChild(SVG('circle',{cx:cx+a*sx,cy:cy-b*sy,r:5,fill:'var(--yellow)',stroke:'var(--ink)'}));
      }
      return;
    }
    // finite field
    const p = res.p;
    const cell = Math.min(28, Math.floor(220/p));
    const gridW = p*cell, gridH = p*cell;
    const ox = 320 - gridW/2, oy = 130 - gridH/2;
    svg.appendChild(SVG('rect',{x:ox,y:oy,width:gridW,height:gridH,fill:'#0b0f16',stroke:'var(--line)'}));
    for(let i=0;i<=p;i++){
      svg.appendChild(SVG('line',{x1:ox+i*cell,y1:oy,x2:ox+i*cell,y2:oy+gridH,stroke:'var(--line)','stroke-width':0.5}));
      svg.appendChild(SVG('line',{x1:ox,y1:oy+i*cell,x2:ox+gridW,y2:oy+i*cell,stroke:'var(--line)','stroke-width':0.5}));
    }
    for(const [a,b] of res.pts){
      svg.appendChild(SVG('circle',{
        cx:ox + a*cell + cell/2,
        cy:oy + (p-1-b)*cell + cell/2,
        r:Math.max(3, cell/3),
        fill:'var(--yellow)'
      }));
    }
    const axlab = SVG('text',{x:320, y:oy+gridH+22,'text-anchor':'middle','font-size':12,fill:'var(--mute)'});
    axlab.textContent = `x \u2208 \ud835\udd3d_${p}  (horizontal),   y (vertical)`;
    svg.appendChild(axlab);
    out.textContent = `X(\ud835\udd3d_${p}) has ${res.pts.length} solutions:\n  ` +
      res.pts.map(([a,b])=>`(${a},${b})`).join('  ');
  }
  sel.addEventListener('change', render);
  render();
})();

