(function(){
  const svg = $('#yo-svg'), out = $('#yo-out'), sel = $('#yo-fun');
  const btns = $$('#w-repr button[data-rings]');
  let mode = 'small';
  btns.forEach(b=>b.addEventListener('click', ()=>{
    btns.forEach(x=>x.classList.remove('active')); b.classList.add('active');
    mode = b.dataset.rings; render();
  }));
  const FUN = {
    A1: {repr:'\u2124[t]', fmt:'F(R) = R',
         vals:(R)=> R.elems.slice(),
         push:(x, map)=> map(x)},
    Gm: {repr:'\u2124[t, t\u207b\u00b9]', fmt:'F(R) = R^\u00d7',
         vals:(R)=> R.units.slice(),
         push:(x, map)=> map(x)},
    mu2:{repr:'\u2124[t]/(t\u00b2 \u2212 1)', fmt:'F(R) = { x : x\u00b2 = 1 }',
         vals:(R)=> R.elems.filter(x=> R.mul(x,x)===R.one),
         push:(x, map)=> map(x)},
    mu3:{repr:'\u2124[t]/(t\u00b3 \u2212 1)', fmt:'F(R) = { x : x\u00b3 = 1 }',
         vals:(R)=> R.elems.filter(x=> R.mul(R.mul(x,x),x)===R.one),
         push:(x, map)=> map(x)}
  };
  function FpRing(p){
    const elems = [...Array(p).keys()];
    return {
      name:'\ud835\udd3d_'+p, elems,
      one:1,
      mul:(a,b)=>((a*b)%p+p)%p,
      units: elems.filter(x=> x!==0)
    };
  }
  function Zring(){
    return { name:'\u2124', elems:[-2,-1,0,1,2], one:1,
      mul:(a,b)=>a*b,
      units:[-1,1] };
  }
  function Qring(){
    // display-only stand-in
    return { name:'\u211A', elems:['-1','0','1/2','1','2'], one:'1',
      mul:(a,b)=>a+'\u00b7'+b, units:['-1','1/2','1','2'] };
  }
  function render(){
    while(svg.firstChild) svg.removeChild(svg.firstChild);
    const fun = FUN[sel.value];
    let R1, R2, mapLabel, mapFn;
    if(mode==='small'){
      R1 = Zring(); R2 = FpRing(5);
      mapLabel = '\u2124 \u2192 \ud835\udd3d\u2085 (mod 5)';
      mapFn = (x)=> ((x%5)+5)%5;
    } else if(mode==='f5f7'){
      R1 = FpRing(5); R2 = FpRing(7);
      mapLabel = 'no ring map \ud835\udd3d\u2085 \u2192 \ud835\udd3d\u2087 in CRing';
      mapFn = null;
    } else {
      R1 = Zring(); R2 = Qring();
      mapLabel = '\u2124 \u21aa \u211A (inclusion)';
      mapFn = (x)=> String(x);
    }
    // header: the representing ring
    const hdr = SVG('text',{x:320,y:26,'text-anchor':'middle','font-size':13,fill:'var(--yellow)'});
    hdr.textContent = `F is represented by A = ${fun.repr}      (so F(R) = Hom(A, R))`;
    svg.appendChild(hdr);
    // left panel: R1 and F(R1)
    drawPanel(40, 55, 260, R1, fun, 'left');
    drawPanel(340, 55, 260, R2, fun, 'right');
    // arrow between rings
    if(mapFn){
      drawArrow(svg, [305,110], [335,110], {color:'var(--cyan)', markerId:'yo-ringmap', label:'map', width:2});
      drawArrow(svg, [305,220], [335,220], {color:'var(--violet)', markerId:'yo-funmap', label:'F(map)', width:2, dash:'4 3'});
    } else {
      const x = SVG('text',{x:320, y:115, 'text-anchor':'middle', 'font-size':14, fill:'var(--pink)'});
      x.textContent = '\u2717'; svg.appendChild(x);
    }
    const lab = SVG('text',{x:320, y:285, 'text-anchor':'middle', 'font-size':12, fill:'var(--mute)'});
    lab.textContent = mapLabel;
    svg.appendChild(lab);
    // compute readout
    const v1 = fun.vals(R1), v2 = fun.vals(R2);
    let lines = [`F = ${fun.fmt}`,
                 `F(${R1.name}) = { ${v1.join(', ')} }   (${v1.length} elements shown)`,
                 `F(${R2.name}) = { ${v2.join(', ')} }   (${v2.length} elements)`];
    if(mapFn){
      const img = v1.map(x=>`${x} \u21a6 ${mapFn(x)}`);
      lines.push(`F(map): ${img.join(',  ')}`);
    }
    out.textContent = lines.join('\n');
  }
  function drawPanel(x, y, w, R, fun, side){
    const h = 220;
    svg.appendChild(SVG('rect',{x,y,width:w,height:h,rx:10,fill:'#11151d',stroke:'var(--line)'}));
    // ring node
    svg.appendChild(SVG('circle',{cx:x+w/2, cy:y+55, r:22, fill:'var(--panel2)',stroke:'var(--blue)'}));
    const t = SVG('text',{x:x+w/2, y:y+60,'text-anchor':'middle','font-size':15,fill:'#fff'});
    t.textContent = R.name; svg.appendChild(t);
    const lab = SVG('text',{x:x+w/2, y:y+95,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
    lab.textContent = 'ring'; svg.appendChild(lab);
    // F(R) set
    const vals = fun.vals(R);
    const setX = x+w/2, setY = y+165;
    svg.appendChild(SVG('ellipse',{cx:setX, cy:setY, rx:w/2-20, ry:28,
      fill:'rgba(131,193,103,0.12)', stroke:'var(--green)','stroke-width':1.2}));
    const capt = SVG('text',{x:setX, y:setY-34,'text-anchor':'middle','font-size':11,fill:'var(--green)'});
    capt.textContent = `F(${R.name})`; svg.appendChild(capt);
    const n = Math.min(vals.length, 7);
    for(let i=0;i<n;i++){
      const px = setX + (i - (n-1)/2) * Math.min(28, (w-60)/Math.max(n,1));
      svg.appendChild(SVG('circle',{cx:px, cy:setY+2, r:3, fill:'var(--yellow)'}));
      const tt = SVG('text',{x:px, y:setY-10, 'text-anchor':'middle','font-size':10, fill:'var(--yellow)'});
      tt.textContent = String(vals[i]); svg.appendChild(tt);
    }
    if(vals.length>n){
      const more = SVG('text',{x:setX + n*15, y:setY+5,'text-anchor':'middle','font-size':10, fill:'var(--mute)'});
      more.textContent = '\u2026'; svg.appendChild(more);
    }
  }
  sel.addEventListener('change', render);
  render();
})();

