(function(){
  const svg = $('#gln-svg'), out = $('#gln-out');
  const selN = $('#gln-n'), selQ = $('#gln-q'), btn = $('#gln-sample');
  function order(n, q){
    let prod = 1n;
    const Q = BigInt(q);
    let qi = 1n;
    for(let i=0;i<n;i++){
      const qn = Q**BigInt(n);
      prod *= (qn - qi);
      qi *= Q;
    }
    return prod;
  }
  function det2(M, p){
    const [a,b,c,d] = [M[0][0],M[0][1],M[1][0],M[1][1]];
    return ((a*d - b*c)%p + p)%p;
  }
  function det3(M, p){
    const m = M;
    let s = 0;
    s += m[0][0]*m[1][1]*m[2][2];
    s += m[0][1]*m[1][2]*m[2][0];
    s += m[0][2]*m[1][0]*m[2][1];
    s -= m[0][2]*m[1][1]*m[2][0];
    s -= m[0][0]*m[1][2]*m[2][1];
    s -= m[0][1]*m[1][0]*m[2][2];
    return ((s%p)+p)%p;
  }
  function randMat(n, p){
    const M = [];
    for(let i=0;i<n;i++){ const row=[]; for(let j=0;j<n;j++) row.push(Math.floor(Math.random()*p)); M.push(row); }
    return M;
  }
  let sampled = null;
  function sample(){
    const n = +selN.value, p = +selQ.value;
    // sample until invertible
    let M, det, tries=0;
    do {
      M = randMat(n, p);
      if(n===1) det = ((M[0][0]%p)+p)%p;
      else if(n===2) det = det2(M, p);
      else det = det3(M, p);
      tries++;
    } while(det===0 && tries<60);
    sampled = {M, det, n, p};
    render();
  }
  function render(){
    while(svg.firstChild) svg.removeChild(svg.firstChild);
    const n = +selN.value, q = +selQ.value;
    const total = q ** (n*n);
    const ord = order(n, q);
    // bar: invertible fraction
    const W = 560, H = 26;
    svg.appendChild(SVG('rect',{x:40,y:30,width:W,height:H,fill:'#11151d',stroke:'var(--line)',rx:6}));
    const frac = Number(ord) / (total);
    svg.appendChild(SVG('rect',{x:40,y:30,width:W*frac,height:H,fill:'var(--yellow)',rx:6}));
    const labl = SVG('text',{x:320,y:48,'text-anchor':'middle','font-size':12,fill:'#111'});
    labl.textContent = `|GL_${n}(\ud835\udd3d_${q})| / q^(n\u00b2) = ${ord}/${total}`;
    svg.appendChild(labl);
    // sampled matrix
    if(sampled && sampled.n===n && sampled.p===q){
      const M = sampled.M;
      const cell = 36;
      const ox = 320 - (n*cell)/2, oy = 90;
      for(let i=0;i<n;i++) for(let j=0;j<n;j++){
        svg.appendChild(SVG('rect',{x:ox+j*cell, y:oy+i*cell, width:cell, height:cell,
          fill:'var(--panel2)', stroke:'var(--line)'}));
        const t = SVG('text',{x:ox+j*cell+cell/2, y:oy+i*cell+cell/2+5, 'text-anchor':'middle','font-size':14,
          fill:'var(--yellow)'});
        t.textContent = M[i][j]; svg.appendChild(t);
      }
      const cap = SVG('text',{x:320, y:oy + n*cell + 20, 'text-anchor':'middle','font-size':12,
        fill: sampled.det===0 ? 'var(--pink)' : 'var(--green)'});
      cap.textContent = sampled.det===0 ? 'singular (not in GL_n)' : `det = ${sampled.det} \u2208 \ud835\udd3d_${q}^\u00d7`;
      svg.appendChild(cap);
    }
    out.textContent = `GL_${n}(\ud835\udd3d_${q}) = invertible ${n}\u00d7${n} matrices over \ud835\udd3d_${q}\n` +
      `order formula: \u220f_{i=0}^{n-1}(q^n - q^i) = ${ord}\n` +
      `ambient: all matrices = q^{n\u00b2} = ${total}\n` +
      `represented by \u2124[x_{ij}, t] / (t\u00b7det(X) - 1)`;
  }
  selN.addEventListener('change', ()=>{sampled=null; render();});
  selQ.addEventListener('change', ()=>{sampled=null; render();});
  btn.addEventListener('click', sample);
  render();
})();

