(function(){
  const svg = $('#dec-svg'), out = $('#dec-out'), sel = $('#dec-fun'), selN = $('#dec-n');
  const TABLE = {
    A1: {name:'\ud835\udd38\u00b9', ring:'\u2124[t]', desc:'a hom \u2124[t]\u2192R is a choice of element t\u21a6r.'},
    Gm: {name:'\ud835\udd3e_m', ring:'\u2124[t, t\u207b\u00b9]',
         desc:'forcing t invertible: homs out land in R\u00d7.'},
    Ga: {name:'\ud835\udd3e_a', ring:'\u2124[t]',
         desc:'same underlying functor as \ud835\udd38\u00b9; the group structure is the coaddition t \u21a6 t\u22971 + 1\u2297t on the Hopf algebra.'},
    mu2:{name:'\u03bc\u2082', ring:'\u2124[t]/(t\u00b2 \u2212 1)',
         desc:'enforces t\u00b2 = 1.'},
    mun:{name:'\u03bc_n', ringFn:(n)=>`\u2124[t]/(t^${n} \u2212 1)`,
         desc:'enforces t^n = 1; a group scheme.'},
    sln:{name:'SL_n', ringFn:(n)=>`\u2124[x_{ij}]_{1\u2264i,j\u2264${n}} / (det(X) \u2212 1)`,
         desc:'closed subscheme of \ud835\udd38^{n\u00b2} carved out by the single equation det(X) = 1.'}
  };
  function render(){
    while(svg.firstChild) svg.removeChild(svg.firstChild);
    const key = sel.value, n = +selN.value;
    const T = TABLE[key];
    const ring = T.ringFn ? T.ringFn(n) : T.ring;
    // LHS
    svg.appendChild(SVG('rect',{x:30,y:30,width:260,height:120,rx:10,fill:'#11151d',stroke:'var(--line)'}));
    const f1 = SVG('text',{x:160,y:60,'text-anchor':'middle','font-size':13,fill:'var(--mute)'});
    f1.textContent = 'functor'; svg.appendChild(f1);
    const f2 = SVG('text',{x:160,y:90,'text-anchor':'middle','font-size':16,fill:'var(--cyan)'});
    f2.textContent = T.name; svg.appendChild(f2);
    const f3 = SVG('text',{x:160,y:120,'text-anchor':'middle','font-size':12,fill:'#fff'});
    f3.textContent = descValue(key, n); svg.appendChild(f3);
    // arrow
    drawArrow(svg, [295,95], [345,95], {color:'var(--yellow)', markerId:'dec-arr', label:'Spec', width:2});
    // RHS
    svg.appendChild(SVG('rect',{x:350,y:30,width:260,height:120,rx:10,fill:'#11151d',stroke:'var(--line)'}));
    const g1 = SVG('text',{x:480,y:60,'text-anchor':'middle','font-size':13,fill:'var(--mute)'});
    g1.textContent = 'representing ring A'; svg.appendChild(g1);
    const g2 = SVG('text',{x:480,y:95,'text-anchor':'middle','font-size':14,fill:'var(--yellow)'});
    g2.textContent = ring; svg.appendChild(g2);
    const g3 = SVG('text',{x:480,y:125,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
    g3.textContent = 'so X = Spec A'; svg.appendChild(g3);
    out.textContent = `${T.name}(R) = ${descValue(key, n)}\nrepresented by A = ${ring}.\nYoneda: ${T.desc}`;
  }
  function descValue(k, n){
    switch(k){
      case 'A1': return 'R';
      case 'Gm': return 'R\u00d7';
      case 'Ga': return '(R, +)';
      case 'mu2': return '{x \u2208 R : x\u00b2 = 1}';
      case 'mun': return `{x \u2208 R : x^${n} = 1}`;
      case 'sln': return `{M \u2208 M_${n}(R) : det M = 1}`;
    }
  }
  sel.addEventListener('change', render);
  selN.addEventListener('change', render);
  render();
})();

